<template>
  <div class="iframe-view-container">
    <!-- 顶部工具栏 -->
    <div class="iframe-toolbar">
      <div class="toolbar-left">
        <el-button
          type="primary"
          icon="el-icon-back"
          size="small"
          @click="goBack"
        >
          返回
        </el-button>
        <span class="iframe-title">{{ title }}</span>
      </div>
      <div class="toolbar-right">
        <el-button
          type="info"
          icon="el-icon-refresh"
          size="small"
          circle
          @click="refreshIframe"
          title="刷新"
        ></el-button>
        <el-button
          type="info"
          :icon="isFullscreen ? 'el-icon-close' : 'el-icon-full-screen'"
          size="small"
          circle
          @click="toggleFullscreen"
          :title="isFullscreen ? '退出全屏' : '全屏'"
        ></el-button>
      </div>
    </div>

    <!-- iframe 容器 -->
    <div class="iframe-wrapper" :class="{ 'is-fullscreen': isFullscreen }">
      <!-- 加载动画 -->
      <div v-show="loading" class="iframe-loading">
        <i class="el-icon-loading"></i>
        <p>正在加载系统...</p>
      </div>

      <!-- 错误提示 -->
      <div v-if="loadError" class="iframe-error">
        <i class="el-icon-warning"></i>
        <h3>无法加载外部系统</h3>
        <p>{{ errorMessage }}</p>
        <el-button type="primary" @click="openInNewWindow">
          在新窗口中打开
        </el-button>
      </div>

      <!-- iframe -->
      <iframe
        v-show="!loadError"
        ref="iframe"
        :src="url"
        frameborder="0"
        class="external-iframe"
        @load="onIframeLoad"
        @error="onIframeError"
      ></iframe>
    </div>
  </div>
</template>

<script>
export default {
  name: "IframeView",
  props: {
    // 外部系统 URL
    url: {
      type: String,
      required: true,
    },
    // 显示标题
    title: {
      type: String,
      default: "外部系统",
    },
  },
  data() {
    return {
      loading: true,
      loadError: false,
      errorMessage: "",
      isFullscreen: false,
      iframeKey: 0,
    };
  },
  mounted() {
    // 监听 iframe 加载超时
    this.loadingTimeout = setTimeout(() => {
      if (this.loading) {
        this.loading = false;
        this.loadError = true;
        this.errorMessage =
          "系统加载超时，可能是由于网络问题或该系统不支持嵌入显示。请尝试在新窗口中打开。";
      }
    }, 30000); // 30秒超时
  },
  beforeDestroy() {
    if (this.loadingTimeout) {
      clearTimeout(this.loadingTimeout);
    }
  },
  methods: {
    // iframe 加载完成
    onIframeLoad() {
      clearTimeout(this.loadingTimeout);
      this.loading = false;

      // 尝试检测是否被 X-Frame-Options 阻止
      try {
        const iframe = this.$refs.iframe;
        // 尝试访问 iframe 内容，如果跨域会抛出异常
        const iframeDoc = iframe.contentDocument || iframe.contentWindow.document;
        if (!iframeDoc || iframeDoc.body.innerHTML === "") {
          // 可能被阻止了
          setTimeout(() => {
            if (this.$refs.iframe && !this.$refs.iframe.contentWindow.location.href) {
              this.loadError = true;
              this.errorMessage =
                "该系统不允许在 iframe 中显示（X-Frame-Options 限制）。请在新窗口中打开。";
            }
          }, 1000);
        }
      } catch (e) {
        // 跨域访问异常是正常的，不做处理
      }
    },

    // iframe 加载错误
    onIframeError() {
      clearTimeout(this.loadingTimeout);
      this.loading = false;
      this.loadError = true;
      this.errorMessage = "无法加载该系统，请检查 URL 是否正确或在新窗口中打开。";
    },

    // 刷新 iframe
    refreshIframe() {
      this.loading = true;
      this.loadError = false;
      const iframe = this.$refs.iframe;
      if (iframe) {
        iframe.src = iframe.src;
      }
    },

    // 在新窗口打开
    openInNewWindow() {
      window.open(this.url, "_blank");
    },

    // 返回
    goBack() {
      if (this.isFullscreen) {
        this.exitFullscreen();
      }
      this.$router.go(-1);
    },

    // 切换全屏
    toggleFullscreen() {
      if (this.isFullscreen) {
        this.exitFullscreen();
      } else {
        this.enterFullscreen();
      }
    },

    // 进入全屏
    enterFullscreen() {
      this.isFullscreen = true;
      document.body.classList.add("iframe-fullscreen");
    },

    // 退出全屏
    exitFullscreen() {
      this.isFullscreen = false;
      document.body.classList.remove("iframe-fullscreen");
    },
  },
};
</script>

<style lang="scss" scoped>
.iframe-view-container {
  position: relative;
  width: 100%;
  height: calc(100vh - 104px);
  background-color: #fff;
  border-radius: 4px;
  overflow: hidden;
  box-shadow: 0 2px 12px 0 rgba(0, 0, 0, 0.1);

  // 顶部工具栏
  .iframe-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px 20px;
    background-color: #f5f7fa;
    border-bottom: 1px solid #e4e7ed;

    .toolbar-left {
      display: flex;
      align-items: center;
      gap: 15px;

      .iframe-title {
        font-size: 16px;
        font-weight: 600;
        color: #303133;
      }
    }

    .toolbar-right {
      display: flex;
      gap: 10px;
    }
  }

  // iframe 包装器
  .iframe-wrapper {
    position: relative;
    width: 100%;
    height: calc(100% - 52px);
    background-color: #fff;

    &.is-fullscreen {
      position: fixed;
      top: 0;
      left: 0;
      width: 100vw;
      height: 100vh;
      z-index: 9999;

      .iframe-toolbar {
        position: absolute;
        top: 0;
        left: 0;
        right: 0;
        z-index: 10000;
      }

      .external-iframe {
        height: calc(100vh - 52px);
        margin-top: 52px;
      }
    }

    // 加载动画
    .iframe-loading {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      text-align: center;
      z-index: 10;

      i {
        font-size: 48px;
        color: #409eff;
        margin-bottom: 15px;
      }

      p {
        font-size: 16px;
        color: #606266;
        margin: 0;
      }
    }

    // 错误提示
    .iframe-error {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      text-align: center;
      z-index: 10;

      i {
        font-size: 64px;
        color: #f56c6c;
        margin-bottom: 20px;
      }

      h3 {
        font-size: 20px;
        color: #303133;
        margin: 0 0 10px 0;
      }

      p {
        font-size: 14px;
        color: #909399;
        margin: 0 0 20px 0;
        max-width: 400px;
        line-height: 1.6;
      }
    }

    // iframe
    .external-iframe {
      width: 100%;
      height: 100%;
      border: none;
      background-color: #fff;
    }
  }
}
</style>

<style>
/* 全屏时隐藏门户布局 */
body.iframe-fullscreen {
  overflow: hidden;
}

body.iframe-fullscreen .app-wrapper .sidebar-container,
body.iframe-fullscreen .app-wrapper .fixed-header {
  display: none !important;
}

body.iframe-fullscreen .app-wrapper .main-container {
  margin-left: 0 !important;
}
</style>
